    }

    /* ===== FOLLOWERS & FOLLOWING ===== */
    .profile-connections-grid {
        display: grid;
        grid-template-columns: repeat(2, minmax(0, 1fr));
        gap: 24px;
        margin-bottom: 24px;
    }

    .connections-section {
        margin-bottom: 0;
    }

    .followers-grid {
        display: grid;
        gap: 12px;
    }

    .follower-card {
        display: flex;
        align-items: center;
        gap: 12px;
        padding: 12px;
        background-color: var(--bg-light);
        border-radius: 10px;
        border: 1px solid var(--border-color);
        transition: all 0.2s ease;
    }

    .follower-card:hover {
        background-color: #f0f4ff;
        border-color: var(--primary-color);
    }

    .follower-avatar {
        width: 40px;
        height: 40px;
        border-radius: 50%;
        background: linear-gradient(135deg, var(--primary-color), var(--secondary-color));
        color: white;
        display: flex;
        align-items: center;
        justify-content: center;
        font-weight: 700;
        font-size: 16px;
        flex-shrink: 0;
    }

    .follower-info {
        flex: 1;
        min-width: 0;
    }

    .follower-info h4 {
        margin: 0;
        font-size: 13px;
        color: var(--text-dark);
        font-weight: 600;
        white-space: nowrap;
        overflow: hidden;
        text-overflow: ellipsis;
    }

    .follower-info p {
        margin: 2px 0 0;
        font-size: 11px;
        color: var(--text-light);
    }

    .follower-link {
        width: 28px;
        height: 28px;
        border-radius: 50%;
        background: var(--primary-color);
        color: white;
        display: flex;
        align-items: center;
        justify-content: center;
        flex-shrink: 0;
        transition: all 0.2s ease;
        text-decoration: none;
        font-size: 12px;
    }

    .follower-link:hover {
        background: var(--secondary-color);
        transform: scale(1.1);
    }

    .view-more-hint {
        margin-top: 12px;
        padding: 10px;
        background-color: var(--bg-light);
        border-radius: 8px;
        text-align: center;
    }

    .view-more-hint small {
        color: var(--text-light);
        font-size: 12px;
    }

    .view-more-hint i {
        color: var(--primary-color);
        margin-right: 4px;
    }

    .not-interested-list {
        display: grid;
        gap: 12px;
    }

    .not-interested-item {
        border: 1px solid var(--border-color);
        border-radius: 10px;
        padding: 14px;
        background: #f8fafc;
    }

    .not-interested-head {
        display: flex;
        justify-content: space-between;
        gap: 10px;
        align-items: baseline;
        margin-bottom: 8px;
    }

    .not-interested-head h4 {
        margin: 0;
        color: var(--text-dark);
        font-size: 15px;
        font-weight: 700;
    }

    .not-interested-head small {
        color: var(--text-light);
        font-size: 12px;
    }

    .not-interested-reason {
        margin: 0 0 8px;
        color: #374151;
        line-height: 1.55;
    }

    .not-interested-meta {
        margin: 0;
        color: var(--text-light);
        font-size: 13px;
    }

    /* ===== RESPONSIVE ===== */
    @media (max-width: 768px) {
        .profile-header-content {
            flex-direction: column;
            gap: 24px;
        }

        .profile-avatar-large {
            width: 100px;
            height: 100px;
            font-size: 40px;
        }

        .profile-username {
            font-size: 24px;
        }

        .profile-header {
            padding: 30px;
            margin-bottom: 24px;
        }

        .profile-actions {
            flex-direction: column;
        }

        .btn {
            width: 100%;
            text-align: center;
        }

        .profile-stats {
            grid-template-columns: 1fr;
        }

        .details-grid {
            grid-template-columns: 1fr;
        }

        .activity-stats {
            grid-template-columns: 1fr;
        }

        .profile-connections-grid {
            grid-template-columns: 1fr;
        }
    }
</style>
{% endblock %}
